operation.expression:
let $startPos := string-length(substring-before($temp.Tmp_LLM_Response   , 'Summary:')) + string-length('Summary:')
let $endPos := string-length(substring-before($temp.Tmp_LLM_Response  , 'Description:'))
let $length := $endPos - $startPos
let $result := substring($temp.Tmp_LLM_Response  , $startPos + 1, $length)
return normalize-space($result)

let $links_list := string-join(
  for $obj in $output.Out_Embeddings_Model_PO 
  return string($obj/JiraLink ),
  '&#10;'
)

return concat(
  "Thank you for reaching out to us.", "&#10;", "&#10;",
  "During our review, we identified ", count($output.Out_Embeddings_Model_PO), " existing Jira ticket(s) that address similar topics or issues. These may provide useful context or indicate ongoing work in related areas.", "&#10;",
  "Below is a list of similar tickets, ordered by relevance:", "&#10;",
  $links_list, "&#10;", "&#10;",

  "If the information provided meets your expectations, please mark the ticket as *solved*.", "&#10;",
  "If not, feel free to mark it as *open* again and provide additional details or questions.", "&#10;", "&#10;"
)
